code = """import json
# Load data
with open('var_functions.query_db:2', 'r') as f:
    civic_docs = json.load(f)

funding_results = locals()['var_functions.query_db:28']

# Build dictionary of project statuses from civic documents
proj_status = {}

# Simple matching approach - look for project name mentions with context
for doc in civic_docs:
    text = doc.get('text', '')
    t = text.lower()
    
    # For each funding project, check if mentioned and get status
    for rec in funding_results:
        pname = rec['Project_Name'].lower()
        # Clean name for partial matching
        clean_pname = pname.replace(' (fema project)', '').replace(' (fema/caloes project)', '').replace(' (fema)', '')
        
        if clean_pname in t:
            # Find status
            if 'construction was completed' in t:
                proj_status[pname] = 'completed'
            elif 'under construction' in t:
                proj_status[pname] = 'construction'
            elif 'complete design' in t or 'finalize design' in t:
                proj_status[pname] = 'design'
            elif 'not started' in t:
                proj_status[pname] = 'not started'

print('Extracted %d statuses' % len(proj_status))

# Build final results list
final_list = []
for rec in funding_results:
    name = rec['Project_Name']
    name_lower = name.lower()
    
    status = proj_status.get(name_lower, 'Unknown')
    
    final_list.append({
        'Project_Name': name,
        'Funding_Source': rec['Funding_Source'],
        'Amount': int(rec['Amount']),
        'Status': status,
        'Type': 'disaster'
    })

# Sort by amount
final_list.sort(key=lambda x: x['Amount'], reverse=True)

import json as js
print('__RESULT__:')
print(js.dumps(final_list))"""

